using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut;

    [TestInitialize]
    public void TestInitialize()
    {
        _sut = new NotificationService();
        // Drain the static queue to avoid interference from other tests
        while (_sut.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _sut?.Dispose();
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        var result = _sut.ReceiveNotification();

        Assert.IsNull(result);
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_EnqueuesNotification()
    {
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        var notification = _sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesEntityIdInMessage()
    {
        _sut.SendNotification("Student", "42", EntityOperation.CREATE);

        var notification = _sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_IncludesDisplayNameInMessage()
    {
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

        var notification = _sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, "New Student 'Test' has been created", DisplayName = "CREATE message")]
    [DataRow(EntityOperation.UPDATE, "Student 'Test' has been updated", DisplayName = "UPDATE message")]
    [DataRow(EntityOperation.DELETE, "Student 'Test' has been deleted", DisplayName = "DELETE message")]
    public void SendNotification_GeneratesCorrectMessageForOperation(EntityOperation operation, string expectedMessage)
    {
        _sut.SendNotification("Student", "1", "Test", operation);

        var notification = _sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual(expectedMessage, notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        var notification = _sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAt()
    {
        var before = DateTime.Now.AddSeconds(-1);
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);
        var after = DateTime.Now.AddSeconds(1);

        var notification = _sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before, $"CreatedAt {notification.CreatedAt} should be >= {before}");
        Assert.IsTrue(notification.CreatedAt <= after, $"CreatedAt {notification.CreatedAt} should be <= {after}");
    }

    [TestMethod]
    public void ReceiveNotification_MultipleSends_ReturnsFIFOOrder()
    {
        _sut.SendNotification("Student", "1", "First", EntityOperation.CREATE);
        _sut.SendNotification("Student", "2", "Second", EntityOperation.UPDATE);
        _sut.SendNotification("Student", "3", "Third", EntityOperation.DELETE);

        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();
        var third = _sut.ReceiveNotification();

        Assert.AreEqual("1", first.EntityId);
        Assert.AreEqual("2", second.EntityId);
        Assert.AreEqual("3", third.EntityId);
    }

    [TestMethod]
    public void ReceiveNotification_AfterAllConsumed_ReturnsNull()
    {
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        _sut.ReceiveNotification(); // consume the one notification
        var result = _sut.ReceiveNotification();

        Assert.IsNull(result);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op for in-memory implementation
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(999);
        _sut.MarkAsRead(-1);
    }

    [TestMethod]
    public void Dispose_CanBeCalledMultipleTimes()
    {
        _sut.Dispose();
        _sut.Dispose(); // Should not throw
    }

    [TestMethod]
    public void SendNotification_OverloadWithoutDisplayName_SetsCorrectProperties()
    {
        _sut.SendNotification("Course", "101", EntityOperation.DELETE, "TestUser");

        var notification = _sut.ReceiveNotification();

