using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.EntityFrameworkCore;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class HomeControllerTests
{
    private SchoolContext CreateContext()
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
            .Options;
        return new SchoolContext(options);
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        using var context = CreateContext();
        using var controller = new HomeController(context);

        var result = controller.Index();

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void About_WithStudents_ReturnsViewWithEnrollmentDateGroups()
    {
        using var context = CreateContext();
        var date1 = new DateTime(2023, 9, 1);
        var date2 = new DateTime(2024, 1, 15);
        context.Students.AddRange(
            new Student { FirstMidName = "Alice", LastName = "Smith", EnrollmentDate = date1 },
            new Student { FirstMidName = "Bob", LastName = "Jones", EnrollmentDate = date1 },
            new Student { FirstMidName = "Carol", LastName = "White", EnrollmentDate = date2 }
        );
        context.SaveChanges();

        using var controller = new HomeController(context);

        var result = controller.About() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
        var group1 = model.Single(g => g.EnrollmentDate == date1);
        Assert.AreEqual(2, group1.StudentCount);
        var group2 = model.Single(g => g.EnrollmentDate == date2);
        Assert.AreEqual(1, group2.StudentCount);
    }

    [TestMethod]
    public void About_NoStudents_ReturnsEmptyList()
    {
        using var context = CreateContext();
        using var controller = new HomeController(context);

        var result = controller.About() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    [TestMethod]
    public void Contact_ReturnsViewWithMessage()
    {
        using var context = CreateContext();
        using var controller = new HomeController(context);

        var result = controller.Contact() as ViewResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Your contact page.", controller.ViewBag.Message);
    }

    [TestMethod]
    public void Error_ReturnsViewResult()
    {
        using var context = CreateContext();
        using var controller = new HomeController(context);

        var result = controller.Error();

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Unauthorized_ReturnsViewWithMessage()
    {
        using var context = CreateContext();
        using var controller = new HomeController(context);

        var result = controller.Unauthorized() as ViewResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("You don't have permission to access this resource.", controller.ViewBag.Message);
    }
}

