using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.EntityFrameworkCore;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using System.Net;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class DepartmentsControllerTests
{
    private SchoolContext CreateContext(string dbName = null)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName ?? Guid.NewGuid().ToString())
            .Options;
        return new SchoolContext(options);
    }

    private void SeedInstructor(SchoolContext context, string firstName = "John", string lastName = "Doe")
    {
        context.Instructors.Add(new Instructor
        {
            FirstMidName = firstName,
            LastName = lastName,
            HireDate = new DateTime(2020, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        });
        context.SaveChanges();
    }

    private Department SeedDepartment(SchoolContext context, string name = "Engineering", int? instructorId = null)
    {
        var dept = new Department
        {
            Name = name,
            Budget = 100000m,
            StartDate = new DateTime(2020, 1, 1),
            InstructorID = instructorId
        };
        context.Departments.Add(dept);
        context.SaveChanges();
        return dept;
    }

    #region Index Tests

    [TestMethod]
    public void Index_ReturnsViewWithAllDepartments()
    {
        using var context = CreateContext();
        SeedDepartment(context, "CS");
        SeedDepartment(context, "Math");
        using var controller = new DepartmentsController(context);

        var result = controller.Index() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as List<Department>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
    }

    [TestMethod]
    public void Index_NoDepartments_ReturnsEmptyList()
    {
        using var context = CreateContext();
        using var controller = new DepartmentsController(context);

        var result = controller.Index() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as List<Department>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    #endregion

    #region Details Tests

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        using var context = CreateContext();
        using var controller = new DepartmentsController(context);

        var result = controller.Details(null) as StatusCodeResult;

        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [TestMethod]
    public void Details_NonExistentId_ReturnsNotFound()
    {
        using var context = CreateContext();
        using var controller = new DepartmentsController(context);

        var result = controller.Details(9999) as NotFoundResult;

        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsDepartmentView()
    {
        using var context = CreateContext();
        var dept = SeedDepartment(context, "Physics");
        using var controller = new DepartmentsController(context);

        var result = controller.Details(dept.DepartmentID) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.IsNotNull(model);
        Assert.AreEqual("Physics", model.Name);
    }

    #endregion

    #region Create Tests

    [TestMethod]
    public void Create_Get_ReturnsViewWithInstructorSelectList()
    {
        using var context = CreateContext();
        SeedInstructor(context);
        using var controller = new DepartmentsController(context);

        var result = controller.Create() as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsNotNull(controller.ViewBag.InstructorID);
    }

    [TestMethod]
    public void Create_Post_ValidDepartment_RedirectsToIndex()
    {
        using var context = CreateContext();
        using var controller = new DepartmentsController(context);
        var department = new Department
        {
            Name = "New Department",
            Budget = 50000m,
            StartDate = new DateTime(2024, 1, 1)
        };

        var result = controller.Create(department) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Create_Post_ValidDepartment_SavesToDB()
    {
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        using var controller = new DepartmentsController(context);
        var department = new Department
        {
            Name = "New Department",
            Budget = 75000m,
            StartDate = new DateTime(2024, 6, 1)
        };

        controller.Create(department);

        using var verifyContext = CreateContext(dbName);
        var saved = verifyContext.Departments.Single();
        Assert.AreEqual("New Department", saved.Name);
        Assert.AreEqual(75000m, saved.Budget);
        Assert.AreEqual(new DateTime(2024, 6, 1), saved.StartDate);
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsViewWithDepartment()
    {
        using var context = CreateContext();
        SeedInstructor(context);
        using var controller = new DepartmentsController(context);
        controller.ModelState.AddModelError("Name", "Required");
        var department = new Department { Budget = 50000m };

        var result = controller.Create(department) as ViewResult;

        Assert.IsNotNull(result);
        Assert.AreEqual(department, result.Model);
        Assert.IsNotNull(controller.ViewBag.InstructorID);
    }

    #endregion

    #region Edit Tests

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        using var context = CreateContext();
        using var controller = new DepartmentsController(context);

        var result = controller.Edit((int?)null) as StatusCodeResult;

        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_NonExistentId_ReturnsNotFound()
    {
        using var context = CreateContext();
        using var controller = new DepartmentsController(context);

        var result = controller.Edit(9999) as NotFoundResult;

        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsDepartmentView()
    {
        using var context = CreateContext();
        SeedInstructor(context);
        var dept = SeedDepartment(context, "Biology");
        using var controller = new DepartmentsController(context);

        var result = controller.Edit(dept.DepartmentID) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.IsNotNull(model);
        Assert.AreEqual("Biology", model.Name);
        Assert.IsNotNull(controller.ViewBag.InstructorID);
    }

    [TestMethod]
    public void Edit_Post_ValidDepartment_RedirectsToIndex()
    {
        var dbName = Guid.NewGuid().ToString();
        int deptId;
        using (var seedContext = CreateContext(dbName))
        {
            var dept = SeedDepartment(seedContext, "Old Name");
            deptId = dept.DepartmentID;
        }

        using var context = CreateContext(dbName);
        SeedInstructor(context);
        using var controller = new DepartmentsController(context);
        var editedDept = new Department
        {
            DepartmentID = deptId,
            Name = "New Name",
            Budget = 200000m,
            StartDate = new DateTime(2024, 1, 1)
        };

        var result = controller.Edit(editedDept) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        using var context = CreateContext();
        SeedInstructor(context);
        using var controller = new DepartmentsController(context);
        controller.ModelState.AddModelError("Name", "Required");
        var department = new Department
        {
            DepartmentID = 1,
            Budget = 50000m,
            StartDate = new DateTime(2024, 1, 1)
        };

        var result = controller.Edit(department) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsNotNull(controller.ViewBag.InstructorID);
    }

    #endregion

    #region Delete Tests

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        using var context = CreateContext();
        using var controller = new DepartmentsController(context);

        var result = controller.Delete(null) as StatusCodeResult;

        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_NonExistentId_ReturnsNotFound()
    {
        using var context = CreateContext();
        using var controller = new DepartmentsController(context);

        var result = controller.Delete(9999) as NotFoundResult;

        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsDepartmentView()
    {
        using var context = CreateContext();
        var dept = SeedDepartment(context, "Chemistry");
        using var controller = new DepartmentsController(context);

        var result = controller.Delete(dept.DepartmentID) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.IsNotNull(model);
        Assert.AreEqual("Chemistry", model.Name);
    }

    [TestMethod]
    public void DeleteConfirmed_RemovesDepartmentAndRedirects()
    {
        var dbName = Guid.NewGuid().ToString();
        int deptId;
        using (var seedContext = CreateContext(dbName))
        {
            var dept = SeedDepartment(seedContext, "ToDelete");
            deptId = dept.DepartmentID;
        }

        using var context = CreateContext(dbName);
        using var controller = new DepartmentsController(context);

        var result = controller.DeleteConfirmed(deptId) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);

        using var verifyContext = CreateContext(dbName);
        Assert.AreEqual(0, verifyContext.Departments.Count());
    }

    #endregion
}

