using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.EntityFrameworkCore;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using System.Net;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class InstructorsControllerTests
{
    private SchoolContext CreateContext(string dbName = null)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName ?? Guid.NewGuid().ToString())
            .Options;
        return new SchoolContext(options);
    }

    private void SeedFullInstructorData(SchoolContext context, out int instructorId, out int courseId)
    {
        var department = new Department
        {
            DepartmentID = 1,
            Name = "Computer Science",
            Budget = 100000m,
            StartDate = new DateTime(2020, 1, 1)
        };
        context.Departments.Add(department);

        var course = new Course
        {
            CourseID = 1001,
            Title = "Programming 101",
            Credits = 3,
            DepartmentID = 1,
            Enrollments = new List<Enrollment>()
        };
        context.Courses.Add(course);

        var instructor = new Instructor
        {
            FirstMidName = "John",
            LastName = "Doe",
            HireDate = new DateTime(2020, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };
        context.Instructors.Add(instructor);
        context.SaveChanges();

        var officeAssignment = new OfficeAssignment
        {
            InstructorID = instructor.ID,
            Location = "Room 101"
        };
        context.OfficeAssignments.Add(officeAssignment);

        var courseAssignment = new CourseAssignment
        {
            InstructorID = instructor.ID,
            CourseID = 1001
        };
        context.CourseAssignments.Add(courseAssignment);
        context.SaveChanges();

        instructorId = instructor.ID;
        courseId = course.CourseID;
    }

    #region Index Tests

    [TestMethod]
    public void Index_NoParameters_ReturnsViewWithInstructors()
    {
        using var context = CreateContext();
        SeedFullInstructorData(context, out _, out _);
        using var controller = new InstructorsController(context);

        var result = controller.Index(null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Instructors);
        Assert.AreEqual(1, model.Instructors.Count());
    }

    [TestMethod]
    public void Index_WithInstructorId_PopulatesCourses()
    {
        using var context = CreateContext();
        SeedFullInstructorData(context, out int instructorId, out _);
        using var controller = new InstructorsController(context);

        var result = controller.Index(instructorId, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Courses);
        Assert.AreEqual(1, model.Courses.Count());
        Assert.AreEqual("Programming 101", model.Courses.First().Title);
        Assert.AreEqual(instructorId, (int)controller.ViewBag.InstructorID);
    }

    [TestMethod]
    public void Index_NoInstructors_ReturnsEmptyView()
    {
        using var context = CreateContext();
        using var controller = new InstructorsController(context);

        var result = controller.Index(null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Instructors.Count());
    }

    #endregion

    #region Details Tests

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        using var context = CreateContext();
        using var controller = new InstructorsController(context);

        var result = controller.Details(null) as StatusCodeResult;

        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [TestMethod]
    public void Details_NonExistentId_ReturnsNotFound()
    {
        using var context = CreateContext();
        using var controller = new InstructorsController(context);

        var result = controller.Details(9999) as NotFoundResult;

        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsInstructorView()
    {
        using var context = CreateContext();
        var instructor = new Instructor
        {
            FirstMidName = "Jane",
            LastName = "Smith",
            HireDate = new DateTime(2021, 3, 15),
            CourseAssignments = new List<CourseAssignment>()
        };
        context.Instructors.Add(instructor);
        context.SaveChanges();
        using var controller = new InstructorsController(context);

        var result = controller.Details(instructor.ID) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual("Jane", model.FirstMidName);
        Assert.AreEqual("Smith", model.LastName);
    }

    #endregion

    #region Create Tests

    [TestMethod]
    public void Create_Get_ReturnsViewWithInstructorAndCourses()
    {
        using var context = CreateContext();
        context.Courses.Add(new Course { CourseID = 101, Title = "Math", Credits = 3, DepartmentID = 0 });
        context.SaveChanges();
        using var controller = new InstructorsController(context);

        var result = controller.Create() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.CourseAssignments);
        Assert.AreEqual(0, model.CourseAssignments.Count);

        var courses = controller.ViewBag.Courses as List<AssignedCourseData>;
        Assert.IsNotNull(courses);
        Assert.AreEqual(1, courses.Count);
        Assert.AreEqual("Math", courses[0].Title);
        Assert.IsFalse(courses[0].Assigned);
    }

    [TestMethod]
    public void Create_Post_ValidInstructor_RedirectsToIndex()
    {
        using var context = CreateContext();
        using var controller = new InstructorsController(context);
        var instructor = new Instructor
        {
            FirstMidName = "New",
            LastName = "Instructor",
            HireDate = new DateTime(2024, 1, 1)
        };

        var result = controller.Create(instructor, null) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Create_Post_ValidInstructor_SavesInstructorToDatabase()
    {
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        using var controller = new InstructorsController(context);
        var instructor = new Instructor
        {
            FirstMidName = "New",
            LastName = "Instructor",
            HireDate = new DateTime(2024, 1, 1)
        };

        controller.Create(instructor, null);

        using var verifyContext = CreateContext(dbName);
        var saved = verifyContext.Instructors.Single();
        Assert.AreEqual("New", saved.FirstMidName);
        Assert.AreEqual("Instructor", saved.LastName);
        Assert.AreEqual(new DateTime(2024, 1, 1), saved.HireDate);
    }

    [TestMethod]
    public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
    {
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        context.Courses.Add(new Course { CourseID = 101, Title = "Math", Credits = 3, DepartmentID = 0 });
        context.Courses.Add(new Course { CourseID = 102, Title = "Science", Credits = 4, DepartmentID = 0 });
        context.SaveChanges();

        using var controller = new InstructorsController(context);
        var instructor = new Instructor
        {
            FirstMidName = "New",
            LastName = "Instructor",
            HireDate = new DateTime(2024, 1, 1)
        };

        controller.Create(instructor, new[] { "101", "102" });

        using var verifyContext = CreateContext(dbName);
        var saved = verifyContext.Instructors.Include(i => i.CourseAssignments).Single();
        Assert.AreEqual(2, saved.CourseAssignments.Count);
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        using var context = CreateContext();
        context.Courses.Add(new Course { CourseID = 101, Title = "Math", Credits = 3, DepartmentID = 0 });
        context.SaveChanges();
        using var controller = new InstructorsController(context);
        controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            FirstMidName = "Test",
            HireDate = new DateTime(2024, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = controller.Create(instructor, null) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsNotNull(controller.ViewBag.Courses);
    }

    #endregion

    #region Edit GET Tests

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        using var context = CreateContext();
        using var controller = new InstructorsController(context);

        var result = controller.Edit((int?)null) as StatusCodeResult;

        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsInstructorView()
    {
        using var context = CreateContext();
        SeedFullInstructorData(context, out int instructorId, out _);
        using var controller = new InstructorsController(context);

        var result = controller.Edit(instructorId) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual("John", model.FirstMidName);
        Assert.IsNotNull(controller.ViewBag.Courses);
    }

    #endregion

    #region Edit POST Tests

    [TestMethod]
    public async Task Edit_Post_NullId_ReturnsBadRequest()
    {
        using var context = CreateContext();
        using var controller = new InstructorsController(context);

        var result = await controller.Edit(null, null) as StatusCodeResult;

        Assert.IsNotNull(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
    }

    #endregion

