using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.EntityFrameworkCore;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext CreateContext()
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
            .Options;
        return new SchoolContext(options);
    }

    [TestInitialize]
    public void TestInitialize()
    {
        // Drain the static notification queue to avoid interference from other tests
        using var service = new NotificationService();
        while (service.ReceiveNotification() != null) { }
    }

    #region GetNotifications Tests

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
    {
        using var context = CreateContext();
        using var controller = new NotificationsController(context);

        var result = controller.GetNotifications();

        Assert.IsNotNull(result);
        var jsonResult = result as JsonResult;
        Assert.IsNotNull(jsonResult);
        // Verify success and count properties exist via dynamic
        var value = jsonResult.Value;
        Assert.IsNotNull(value);
        var successProp = value.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.AreEqual(true, successProp.GetValue(value));
        var countProp = value.GetType().GetProperty("count");
        Assert.IsNotNull(countProp);
        Assert.AreEqual(0, countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotificationsList()
    {
        using var context = CreateContext();
        using var controller = new NotificationsController(context);

        // Enqueue some notifications using the controller's notification service
        // The notificationService field is protected in BaseController, so we send through a helper
        var service = new NotificationService();
        service.SendNotification("Student", "1", "Alice", EntityOperation.CREATE);
        service.SendNotification("Course", "101", "Math", EntityOperation.UPDATE);

        var result = controller.GetNotifications() as JsonResult;

        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);
        var successProp = value.GetType().GetProperty("success");
        Assert.AreEqual(true, successProp.GetValue(value));
        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(2, countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_LimitsToTenNotifications()
    {
        using var context = CreateContext();
        using var controller = new NotificationsController(context);

        // Enqueue 15 notifications
        var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Student", i.ToString(), $"Student{i}", EntityOperation.CREATE);
        }

        var result = controller.GetNotifications() as JsonResult;

        Assert.IsNotNull(result);
        var value = result.Value;
        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(10, countProp.GetValue(value));
    }

    #endregion

    #region MarkAsRead Tests

    [TestMethod]
    public void MarkAsRead_ReturnsSuccess()
    {
        using var context = CreateContext();
        using var controller = new NotificationsController(context);

        var result = controller.MarkAsRead(1) as JsonResult;

        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);
        var successProp = value.GetType().GetProperty("success");
        Assert.AreEqual(true, successProp.GetValue(value));
    }

    [TestMethod]
    public void MarkAsRead_NonExistentId_StillReturnsSuccess()
    {
        using var context = CreateContext();
        using var controller = new NotificationsController(context);

        var result = controller.MarkAsRead(99999) as JsonResult;

        Assert.IsNotNull(result);
        var value = result.Value;
        var successProp = value.GetType().GetProperty("success");
        Assert.AreEqual(true, successProp.GetValue(value));
    }

    #endregion

    #region Index Tests

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        using var context = CreateContext();
        using var controller = new NotificationsController(context);

        var result = controller.Index();

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    #endregion
}

